function PaperFigure({ src, caption, figNum, zoom = false }) {
  const [zoomed, setZoomed] = useState(false);
  return (
    <div style={{ margin: "16px 0" }}>
      <div onClick={() => zoom && setZoomed(!zoomed)} style={{
        position: zoomed ? "fixed" : "relative", borderRadius: 10, overflow: "hidden",
        border: "1px solid #1a2a3a", cursor: zoom ? (zoomed ? "zoom-out" : "zoom-in") : "default",
        ...(zoomed ? { top: 20, left: 20, right: 20, bottom: 20, zIndex: 1000, background: "#060e18" } : {}),
      }}>
        {zoomed && <div style={{ position: "fixed", inset: 0, background: "#000d", zIndex: -1 }} onClick={() => setZoomed(false)} />}
        <img src={src} alt={caption} style={{ width: "100%", display: "block", ...(zoomed ? { objectFit: "contain", height: "100%" } : {}) }} />
      </div>
      <div style={{ display: "flex", gap: 8, alignItems: "baseline", marginTop: 8 }}>
        <span style={{ color: "#00e5ff", fontFamily: "var(--mono)", fontSize: 10, fontWeight: 700 }}>{figNum}</span>
        <span style={{ color: "#5a7a9a", fontFamily: "var(--mono)", fontSize: 10, lineHeight: 1.5 }}>{caption}{zoom && <span style={{ color: "#3a5a7a" }}> — click to zoom</span>}</span>
      </div>
    </div>
  );
}

function DeepBlock({ title, color = "#00e5ff", children, defaultOpen = false }) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div style={{ background: "#0a1520", borderRadius: 10, border: `1px solid ${color}18`, overflow: "hidden", marginBottom: 10 }}>
      <button onClick={() => setOpen(!open)} style={{
        width: "100%", padding: "14px 18px", background: "transparent", border: "none",
        display: "flex", justifyContent: "space-between", alignItems: "center", cursor: "pointer",
      }}>
        <span style={{ color, fontFamily: "var(--mono)", fontSize: 12, fontWeight: 700, textAlign: "left" }}>{title}</span>
        <span style={{ color: "#3a5a7a", fontSize: 16, transition: "transform 0.3s", transform: open ? "rotate(180deg)" : "rotate(0)" }}>▾</span>
      </button>
      {open && <div style={{ padding: "0 18px 18px", borderTop: `1px solid ${color}10` }}>{children}</div>}
    </div>
  );
}

function Callout({ type = "insight", children }) {
  const s = {
    insight: { bg: "#00e5ff08", border: "#00e5ff30", icon: "💡", color: "#8ab4d0" },
    warning: { bg: "#ff6b3508", border: "#ff6b3530", icon: "⚠️", color: "#ff9f43" },
    key: { bg: "#4ade8008", border: "#4ade8030", icon: "🔑", color: "#4ade80" },
    math: { bg: "#b388ff08", border: "#b388ff30", icon: "∑", color: "#b388ff" },
    compare: { bg: "#ffd93d08", border: "#ffd93d30", icon: "⚖️", color: "#ffd93d" },
    limitation: { bg: "#ff444408", border: "#ff444430", icon: "🚧", color: "#ff4444" },
  }[type] || { bg: "#00e5ff08", border: "#00e5ff30", icon: "💡", color: "#8ab4d0" };
  return (
    <div style={{ padding: "12px 16px", background: s.bg, borderRadius: 8, borderLeft: `3px solid ${s.border}`, margin: "10px 0", fontFamily: "var(--mono)", fontSize: 11, color: s.color, lineHeight: 1.7 }}>
      <span style={{ marginRight: 6 }}>{s.icon}</span>{children}
    </div>
  );
}

